import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';
import { UserPlus } from 'lucide-react';

export default function RegisterPage() {
  const { register } = useAuth();
  const navigate = useNavigate();
  const [form, setForm] = useState({ name:'', email:'', password:'', confirm:'' });
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (form.password !== form.confirm) return toast.error('Passwords do not match');
    if (form.password.length < 6)       return toast.error('Password must be at least 6 characters');
    setLoading(true);
    try {
      await register(form.name, form.email, form.password);
      toast.success('Account created! Welcome to RoadAlert.');
      navigate('/dashboard');
    } catch (err) {
      toast.error(err.response?.data?.error || 'Registration failed');
    } finally { setLoading(false); }
  };

  return (
    <div style={{ minHeight:'calc(100vh - 60px)', display:'flex', alignItems:'center', justifyContent:'center', padding:24 }}>
      <div className="card fade-up" style={{ width:'100%', maxWidth:420 }}>
        <div style={{ textAlign:'center', marginBottom:28 }}>
          <div style={{ display:'inline-flex', background:'var(--green-dim)', borderRadius:12, padding:10, marginBottom:14 }}>
            <UserPlus size={24} color="var(--green)"/>
          </div>
          <h2 style={{ fontSize:24, marginBottom:6 }}>Create Account</h2>
          <p style={{ color:'var(--text-muted)', fontSize:14 }}>Join as a civilian reporter</p>
        </div>

        <form onSubmit={handleSubmit} style={{ display:'flex', flexDirection:'column', gap:14 }}>
          {[
            { label:'Full Name',         key:'name',    type:'text',     ph:'John Doe' },
            { label:'Email Address',     key:'email',   type:'email',    ph:'you@example.com' },
            { label:'Password',          key:'password',type:'password', ph:'Min 6 characters' },
            { label:'Confirm Password',  key:'confirm', type:'password', ph:'Re-enter password' },
          ].map(f => (
            <div key={f.key} className="form-group">
              <label className="form-label">{f.label}</label>
              <input className="form-input" type={f.type} placeholder={f.ph} required
                value={form[f.key]} onChange={e => setForm({...form, [f.key]:e.target.value})}/>
            </div>
          ))}
          <button type="submit" className="btn btn-primary"
            style={{ width:'100%', justifyContent:'center', padding:12, marginTop:4 }} disabled={loading}>
            {loading ? 'Creating account…' : 'Create Account'}
          </button>
        </form>

        <p style={{ textAlign:'center', marginTop:18, fontSize:14, color:'var(--text-muted)' }}>
          Already have an account? <Link to="/login" style={{ color:'var(--accent)', fontWeight:600 }}>Sign in</Link>
        </p>
      </div>
    </div>
  );
}
